+                .get_value_and_expiry(&key)
+                .and_then(|(_, expiry)| expiry)
+                .is_some();
+            let entry = per_db.entry(db).or_insert((0, 0));
+            entry.0 = entry.0.saturating_add(1);
+            if expires {
+                entry.1 = entry.1.saturating_add(1);
+            }
+        }
