+    }
+    let mut encoded =
+        Vec::with_capacity(DB_NAMESPACE_PREFIX.len() + std::mem::size_of::<u64>() + key.len());
+    encoded.extend_from_slice(DB_NAMESPACE_PREFIX);
+    encoded.extend_from_slice(&(db as u64).to_be_bytes());
+    encoded.extend_from_slice(key);
